import React from 'react';
import { useApp } from '../context/AppContext';
import MessageCard from './MessageCard';
import EmptyState from './EmptyState';
import LoadingSpinner from './LoadingSpinner';
import '../styles/globals.css';

const MessageList: React.FC = () => {
  const { state } = useApp();

  // Filtrar itens baseado na busca e filtro
  const filteredItems = state.items.filter(item => {
    const matchesSearch = state.searchQuery === '' || 
      (item.name && item.name.toLowerCase().includes(state.searchQuery.toLowerCase())) ||
      (item.subject && item.subject.toLowerCase().includes(state.searchQuery.toLowerCase())) ||
      (item.date && item.date.toLowerCase().includes(state.searchQuery.toLowerCase()));

    let matchesFilter = true;

    // Se estamos na aba de agendamentos (menu ID 5), não aplicar filtro adicional
    // porque os itens já foram carregados corretamente como agendados
    if (state.selectedMenuId === 5) {
      matchesFilter = true;
    } else if (state.selectedMenuId === 6) {
      // Se estamos na aba de arquivados (menu ID 6), não aplicar filtro adicional
      matchesFilter = true;
    } else if (state.selectedMenuId === 4) {
      // Se estamos na aba de lixeira (menu ID 4), não aplicar filtro adicional
      matchesFilter = true;
    } else {
      // Para outros menus (caixa de entrada principal), primeiro verificar se o item não foi arquivado/excluído/agendado
      const isArchived = state.archivedItems.some(archivedItem => archivedItem.id === item.id);
      const isDeleted = state.deletedItems.some(deletedItem => deletedItem.id === item.id);
      const isScheduled = state.scheduledItems.some(scheduledItem => scheduledItem.id === item.id);

      // Se o item foi movido para outra aba, não mostrar na caixa de entrada principal
      if (isArchived || isDeleted || isScheduled) {
        matchesFilter = false;
      } else {
        // Aplicar filtro normal para itens na caixa de entrada
        switch (state.filter) {
          case 'all':
            matchesFilter = true;
            break;
          case 'unread':
            matchesFilter = Boolean(item.subject && !item.subject.includes('[LIDO]'));
            break;
          case 'read':
            matchesFilter = Boolean(item.subject && item.subject.includes('[LIDO]'));
            break;
          case 'scheduled':
            // Para caixa de entrada, mostrar apenas itens não agendados
            matchesFilter = false;
            break;
          case 'archived':
            // Para caixa de entrada, mostrar apenas itens não arquivados
            matchesFilter = false;
            break;
          case 'trash':
            // Para caixa de entrada, mostrar apenas itens não excluídos
            matchesFilter = false;
            break;
          default:
            matchesFilter = true;
        }
      }
    }

    return matchesSearch && matchesFilter;
  });

  if (state.loading) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <LoadingSpinner size="lg" />
      </div>
    );
  }

  if (!state.selectedMenuId) {
    return <EmptyState type="no-selection" language={state.language} />;
  }

  if (filteredItems.length === 0) {
    return <EmptyState type={state.searchQuery ? 'no-results' : 'no-items'} searchQuery={state.searchQuery} language={state.language} />;
  }

  return (
    <div className="flex-1 overflow-auto">
      <div className="divide-y" style={{ borderColor: 'var(--color-border)' }}>
        {filteredItems.map((item) => (
          <MessageCard 
            key={item.id} 
            item={item}
            isAnySelected={state.selectedItems.length > 0}
          />
        ))}
      </div>
    </div>
  );
};

export default MessageList;
